void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv_echo = (vUv - 0.5)*1.010*vec2(-1,-1) + 0.5;
    ret = abs( texture(sampler_main, vUv).xyz -
                    texture(sampler_main, uv_echo).zyx );

  fragColor = ret;
